function initWebflowFormSubmissions(container) {
  const root = container || document;
  const forms = root.querySelectorAll('form');

  forms.forEach(form => {
    if (form._barbaPolyfilled) return;
    form._barbaPolyfilled = true;

    form.addEventListener('submit', function (e) {
      e.preventDefault();
      e.stopPropagation();

      const siteId = document.querySelector('html').getAttribute('data-wf-site');
      const pageId = form.getAttribute('data-wf-page-id');
      const elementId = form.getAttribute('data-wf-element-id');

      const successEl = form.parentElement.querySelector('.w-form-done');
      const errorEl = form.parentElement.querySelector('.w-form-fail');

      const fields = {};
      new FormData(form).forEach((value, key) => {
        fields[key] = value;
      });

      const payload = {
        name: form.getAttribute('data-name') || form.getAttribute('name'),
        pageId: pageId,
        elementId: elementId,
        source: window.location.href,
        test: false,
        fields: fields,
        dolphin: false,
      };

      fetch(`https://webflow.com/api/v1/form/${siteId}`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload),
      })
        .then(res => {
          if (res.ok) {
            form.style.display = 'none';
            if (successEl) successEl.style.display = 'block';
            // Handle redirect if set
            const redirect = form.getAttribute('data-redirect');
            if (redirect) {
              barba.go(redirect);
            }
          } else {
            if (errorEl) errorEl.style.display = 'block';
          }
        })
        .catch(() => {
          if (errorEl) errorEl.style.display = 'block';
        });
    });
  });
}
  
function initCSSMarquee() {
  const pixelsPerSecond = 75; // Set the marquee speed (pixels per second)
  const marquees = document.querySelectorAll('[data-css-marquee]');
  
  // Duplicate each [data-css-marquee-list] element inside its container
  marquees.forEach(marquee => {
    marquee.querySelectorAll('[data-css-marquee-list]').forEach(list => {
      const duplicate = list.cloneNode(true);
      marquee.appendChild(duplicate);
    });
  });

  // Create an IntersectionObserver to check if the marquee container is in view
  const observer = new IntersectionObserver(entries => {
    entries.forEach(entry => {
      entry.target.querySelectorAll('[data-css-marquee-list]').forEach(list => 
        list.style.animationPlayState = entry.isIntersecting ? 'running' : 'paused'
      );
    });
  }, { threshold: 0 });
  
  // Calculate the width and set the animation duration accordingly
  marquees.forEach(marquee => {
    marquee.querySelectorAll('[data-css-marquee-list]').forEach(list => {
      list.style.animationDuration = (list.offsetWidth / pixelsPerSecond) + 's';
      list.style.animationPlayState = 'paused';
    });
    observer.observe(marquee);
  });
}

function initFaqSection() {
  const wraps = document.querySelectorAll("[data-faq-wrap]");
  if (!wraps.length) return;
  wraps.forEach((wrap) => {
    const list = wrap.querySelector("[data-faq-list]");
    if (!list) return;
    const items = Array.from(list.querySelectorAll("[data-faq-item]"));
    const triggers = Array.from(wrap.querySelectorAll("[data-faq-trigger]"));
    if (!items.length || !triggers.length) return;
    let activeIndex = items.findIndex((el) => el.classList.contains("is--active"));
    if (activeIndex < 0) activeIndex = 0;
    let pendingIndex = -1;
    let currentTl = null;
    let reduceMotion = false;
    const slides = items.map((item) => ({
      item,
      tag: item.querySelector("[data-faq-tag]"),
      splitTargets: [
        item.querySelector("[data-faq-heading]"),
        item.querySelector("[data-faq-text]"),
      ].filter(Boolean),
      splitInstances: [],
      getLines() {
        return this.splitInstances.flatMap((instance) => instance.lines);
      },
    }));
    function setSlideState(slideIndex, isActive) {
      const { item } = slides[slideIndex];
      item.classList.toggle("is--active", isActive);
      item.setAttribute("aria-hidden", String(!isActive));
      gsap.set(item, {
        autoAlpha: isActive ? 1 : 0,
        pointerEvents: isActive ? "auto" : "none",
      });
    }
    function updateTriggers(index) {
      triggers.forEach((trigger) => {
        const triggerIndex = parseInt(trigger.getAttribute("data-faq-trigger"));
        trigger.classList.toggle("is--active", triggerIndex === index);
      });
    }
    function snapHidden(slide) {
      gsap.set(slide.item, { autoAlpha: 0, pointerEvents: "none" });
      slide.item.classList.remove("is--active");
      slide.item.setAttribute("aria-hidden", "true");
      if (slide.tag) gsap.set(slide.tag, { autoAlpha: 0, yPercent: 0 });
      gsap.set(slide.getLines(), { yPercent: 110 });
    }
    gsap.matchMedia().add(
      { reduce: "(prefers-reduced-motion: reduce)" },
      (context) => { reduceMotion = context.conditions.reduce; }
    );
    slides.forEach((slide, i) => {
      setSlideState(i, i === activeIndex);
      if (slide.tag && !reduceMotion) {
        gsap.set(slide.tag, {
          autoAlpha: i === activeIndex ? 1 : 0,
          yPercent: i === activeIndex ? 0 : 20,
        });
      }
    });
    updateTriggers(activeIndex);
    slides.forEach((slide, slideIndex) => {
      slide.splitInstances = slide.splitTargets.map((el) =>
        SplitText.create(el, {
          type: "lines",
          mask: "lines",
          linesClass: "text-line",
          autoSplit: true,
          onSplit(self) {
            if (reduceMotion) return;
            const isActive = slideIndex === activeIndex;
            gsap.set(self.lines, { yPercent: isActive ? 0 : 110 });
          },
        })
      );
    });
    function goTo(nextIndex) {
      if (nextIndex === pendingIndex) return;
      if (nextIndex === activeIndex && !currentTl) return;
      const interrupted = !!currentTl;
      if (currentTl) {
        currentTl.kill();
        currentTl = null;
        // Snap every slide except the new target to a clean hidden state
        slides.forEach((slide, i) => {
          if (i !== nextIndex) snapHidden(slide);
        });
      }
      pendingIndex = nextIndex;
      // Update trigger highlight immediately on every navigation
      updateTriggers(nextIndex);
      const outgoingSlide = slides[activeIndex];
      const incomingSlide = slides[nextIndex];
      currentTl = gsap.timeline({
        onComplete: () => {
          // Authoritative final state — hides everything except the target
          slides.forEach((_, i) => setSlideState(i, i === nextIndex));
          activeIndex = nextIndex;
          pendingIndex = -1;
          currentTl = null;
          // Safety net: re-apply trigger state after all state changes settle
          updateTriggers(nextIndex);
        },
      });
      if (reduceMotion) {
        if (!interrupted) {
          currentTl.to(outgoingSlide.item, { autoAlpha: 0, duration: 0.4 }, 0);
        }
        currentTl.fromTo(incomingSlide.item, { autoAlpha: 0 }, { autoAlpha: 1, duration: 0.4 }, 0);
        return;
      }
      const outgoingLines = outgoingSlide.getLines();
      const incomingLines = incomingSlide.getLines();
      gsap.set(incomingSlide.item, { autoAlpha: 1, pointerEvents: "auto" });
      gsap.set(incomingLines, { yPercent: 110 });
      if (!interrupted) {
        // Full transition: both directions animate with overlap
        if (outgoingSlide.tag) {
          currentTl.to(outgoingSlide.tag, {
            autoAlpha: 0,  duration: 0.35, ease: "power3.in",
          }, 0);
        }
        currentTl.to(outgoingLines, {
          yPercent: -110, duration: 0.6, ease: "power4.inOut",
          stagger: { amount: 0.25 },
        }, 0);
        if (incomingSlide.tag) {
          gsap.set(incomingSlide.tag, { autoAlpha: 0, yPercent: 30 });
          currentTl.to(incomingSlide.tag, {
            autoAlpha: 1, yPercent: 0, duration: 0.45, ease: "power3.out",
          }, "<0.1");
        }
        currentTl.to(incomingLines, {
          yPercent: 0, duration: 0.7, ease: "power4.inOut",
          stagger: { amount: 0.4 },
        }, "<0.1");
        currentTl.set(outgoingSlide.item, { autoAlpha: 0 }, ">");
      } else {
        // Interrupted: everything else is already hidden, just bring the target in
        if (incomingSlide.tag) {
          gsap.set(incomingSlide.tag, { autoAlpha: 0, yPercent: 30 });
          currentTl.to(incomingSlide.tag, {
            autoAlpha: 1,  duration: 0.4, ease: "power3.out",
          }, 0);
        }
        currentTl.to(incomingLines, {
          yPercent: 0, duration: 0.55, ease: "power4.out",
          stagger: { amount: 0.25 },
        }, 0);
      }
    }
    triggers.forEach((trigger) => {
      trigger.addEventListener("click", () => {
        const targetIndex = parseInt(trigger.getAttribute("data-faq-trigger"));
        if (!isNaN(targetIndex)) goTo(targetIndex);
      });
    });
    wrap.addEventListener("keydown", (e) => {
      const isTrigger = e.target.hasAttribute("data-faq-trigger");
      if (!isTrigger) return;
      if (e.key === "ArrowDown") {
        e.preventDefault();
        const i = triggers.indexOf(e.target);
        const next = triggers[i + 1];
        if (next) { next.focus(); next.click(); }
      }
      if (e.key === "ArrowUp") {
        e.preventDefault();
        const i = triggers.indexOf(e.target);
        const prev = triggers[i - 1];
        if (prev) { prev.focus(); prev.click(); }
      }
    });
  });
}



function initTabSystem() {
  const wrappers = document.querySelectorAll('[data-tabs="wrapper"]');
  
  wrappers.forEach((wrapper) => {
    const contentItems = wrapper.querySelectorAll('[data-tabs="content-item"]');
    const visualItems = wrapper.querySelectorAll('[data-tabs="visual-item"]');
    
    const autoplay = wrapper.dataset.tabsAutoplay === "true";
    const autoplayDuration = parseInt(wrapper.dataset.tabsAutoplayDuration) || 5000;
    
    let activeContent = null; // keep track of active item/link
    let activeVisual = null;
    let isAnimating = false;
    let progressBarTween = null; // to stop/start the progress bar

    function startProgressBar(index) {
      if (progressBarTween) progressBarTween.kill();
      const bar = contentItems[index].querySelector('[data-tabs="item-progress"]');
      if (!bar) return;
      
      // In this function, you can basically do anything you want, that should happen as a tab is active
      // Maybe you have a circle filling, some other element growing, you name it.
      gsap.set(bar, { scaleX: 0, transformOrigin: "left center" });
      progressBarTween = gsap.to(bar, {
        scaleX: 1,
        duration: autoplayDuration / 1000,
        ease: "power1.inOut",
        onComplete: () => {
          if (!isAnimating) {
            const nextIndex = (index + 1) % contentItems.length;
            switchTab(nextIndex); // once bar is full, set next to active – this is important
          }
        },
      });
    }

    function switchTab(index) {
      if (isAnimating || contentItems[index] === activeContent) return;
      
      isAnimating = true;
      if (progressBarTween) progressBarTween.kill(); // Stop any running progress bar here
      
      const outgoingContent = activeContent;
      const outgoingVisual = activeVisual;
      const outgoingBar = outgoingContent?.querySelector('[data-tabs="item-progress"]');
      
      const incomingContent = contentItems[index];
      const incomingVisual = visualItems[index];
      const incomingBar = incomingContent.querySelector('[data-tabs="item-progress"]');
      
      outgoingContent?.classList.remove("active");
      outgoingVisual?.classList.remove("active");
      incomingContent.classList.add("active");
      incomingVisual.classList.add("active");
      
      const tl = gsap.timeline({
        defaults: { duration: 0.65, ease: "power3" },
        onComplete: () => {
          activeContent = incomingContent;
          activeVisual = incomingVisual;
          isAnimating = false;
          if (autoplay) startProgressBar(index); // Start autoplay bar here
        },
      });
      
      // Wrap 'outgoing' in a check to prevent warnings on first run of the function
      // Of course, during first run (on page load), there's no 'outgoing' tab yet!
      if (outgoingContent) {
        outgoingContent.classList.remove("active");
        outgoingVisual?.classList.remove("active");
        tl.set(outgoingBar, { transformOrigin: "right center" })
          .to(outgoingBar, { scaleX: 0, duration: 0.3 }, 0)
          .to(outgoingVisual, { autoAlpha: 0, xPercent: 3 }, 0)
          .to(outgoingContent.querySelector('[data-tabs="item-details"]'), { height: 0 }, 0);
      }

      incomingContent.classList.add("active");
      incomingVisual.classList.add("active");
      tl.fromTo(incomingVisual, { autoAlpha: 0, xPercent: 3 }, { autoAlpha: 1, xPercent: 0 }, 0)
        .fromTo( incomingContent.querySelector('[data-tabs="item-details"]'),{ height: 0 },{ height: "auto" },0)
        .set(incomingBar, { scaleX: 0, transformOrigin: "left center" }, 0);
    }

    // on page load, set first to active
    // idea: you could wrap this in a scrollTrigger
    // so it will only start once a user reaches this section
    switchTab(0);
    
    // switch tabs on click
    contentItems.forEach((item, i) =>
      item.addEventListener("click", () => {
        if (item === activeContent) return; // ignore click if current one is already active
        switchTab(i);
      })
    );
    
  });
}

function initAccordionCSS() {
  document.querySelectorAll('[data-accordion-css-init]').forEach((accordion) => {
    const closeSiblings = accordion.getAttribute('data-accordion-close-siblings') === 'true';

    accordion.addEventListener('click', (event) => {
      const toggle = event.target.closest('[data-accordion-toggle]');
      if (!toggle) return; // Exit if the clicked element is not a toggle

      const singleAccordion = toggle.closest('[data-accordion-status]');
      if (!singleAccordion) return; // Exit if no accordion container is found

      const isActive = singleAccordion.getAttribute('data-accordion-status') === 'active';
      singleAccordion.setAttribute('data-accordion-status', isActive ? 'not-active' : 'active');
      
      // When [data-accordion-close-siblings="true"]
      if (closeSiblings && !isActive) {
        accordion.querySelectorAll('[data-accordion-status="active"]').forEach((sibling) => {
          if (sibling !== singleAccordion) sibling.setAttribute('data-accordion-status', 'not-active');
        });
      }
    });
  });
}

  
function initProgressNavigation() {
  // Cache the parent container
  let navProgress = document.querySelector('[data-progress-nav-list]');

  // Create or select the moving indicator
  let indicator = navProgress.querySelector('.progress-nav__indicator');
  if (!indicator) {
    indicator = document.createElement('div');
    indicator.className = 'progress-nav__indicator';
    navProgress.appendChild(indicator);
  }
  
function scrollNavToLink(activeLink) {
  activeLink.scrollIntoView({
    behavior: 'smooth',
    block: 'nearest',
    inline: 'center'
  });
}
  
  // Function to update the indicator based on the active nav link
function updateIndicator(activeLink) {
  indicator.style.left = activeLink.offsetLeft + 'px';
  indicator.style.top = activeLink.offsetTop + 'px';
  indicator.style.width = activeLink.offsetWidth + 'px';
  indicator.style.height = activeLink.offsetHeight + 'px';
}
  
  // Get all anchor sections
  let progressAnchors = gsap.utils.toArray('[data-progress-nav-anchor]');

  progressAnchors.forEach((progressAnchor) => {
    let anchorID = progressAnchor.getAttribute('id');
    
    ScrollTrigger.create({
      trigger: progressAnchor,
      start: '0% 50%',
      end: '100% 50%',
      onEnter: () => {
        let activeLink = navProgress.querySelector('[data-progress-nav-target="#' + anchorID + '"]');
        activeLink.classList.add('is--active');
        // Remove 'is--active' class from sibling links
        let siblings = navProgress.querySelectorAll('[data-progress-nav-target]');
        siblings.forEach((sib) => {
          if (sib !== activeLink) {
            sib.classList.remove('is--active');
          }
        });
        updateIndicator(activeLink);
        scrollNavToLink(activeLink);
      },
      onEnterBack: () => {
        let activeLink = navProgress.querySelector('[data-progress-nav-target="#' + anchorID + '"]');
        activeLink.classList.add('is--active');
        // Remove 'is--active' class from sibling links
        let siblings = navProgress.querySelectorAll('[data-progress-nav-target]');
        siblings.forEach((sib) => {
          if (sib !== activeLink) {
            sib.classList.remove('is--active');
          }
        });
        updateIndicator(activeLink);
        scrollNavToLink(activeLink);
      }
    });
  });
}

function initClickToZoomBasic() {

  const CONFIG = {
    openDuration: 0.55,
    closeDuration: 0.45,
    openEase: "power3.out",
    closeEase: "power2.inOut",

    closeOnScroll: true,
    closeOnEscape: true,
    closeOnClick: true,
  };

  const lightbox = document.querySelector("[data-click-zoom-lightbox]");
  if (!lightbox) return;

  lightbox.setAttribute("role", "dialog");
  lightbox.setAttribute("aria-modal", "true");
  lightbox.setAttribute("aria-hidden", "true");

  // Backdrop animates from transparent to the CSS-declared color.
  const backdropColor = window.getComputedStyle(lightbox).backgroundColor;
  const transparent = "rgba(0, 0, 0, 0)";

  let cloneEl = null;
  let isOpen = false;
  let isAnimating = false;
  let openScrollY = 0;
  let openSourceRectDoc = null;

  function computeFlip(src, dst) {
    return {
      scaleX: src.width / dst.width,
      scaleY: src.height / dst.height,
      tx: (src.left + src.width / 2) - (dst.left + dst.width / 2),
      ty: (src.top + src.height / 2) - (dst.top + dst.height / 2),
    };
  }

  function open(img) {
    if (isOpen || isAnimating) return;
    if (!img.complete || !img.naturalWidth) return;

    isAnimating = true;
    openScrollY = window.scrollY;

    const srcRect = img.getBoundingClientRect();
    openSourceRectDoc = {
      top: srcRect.top + window.scrollY,
      left: srcRect.left,
      width: srcRect.width,
      height: srcRect.height,
    };

    cloneEl = img.cloneNode(false);
    cloneEl.loading = "eager";
    cloneEl.removeAttribute("data-click-zoom");

    const srcComputed = window.getComputedStyle(img);

    gsap.set(lightbox, { display: "flex", backgroundColor: transparent });

    const lightboxStyle = window.getComputedStyle(lightbox);
    const padX = parseFloat(lightboxStyle.paddingLeft) + parseFloat(lightboxStyle.paddingRight);
    const padY = parseFloat(lightboxStyle.paddingTop) + parseFloat(lightboxStyle.paddingBottom);
    const aspect = srcRect.width / srcRect.height;
    const maxW = lightbox.clientWidth - padX;
    const maxH = lightbox.clientHeight - padY;
    let w = maxW;
    let h = w / aspect;
    if (h > maxH) { h = maxH; w = h * aspect; }

    gsap.set(cloneEl, {
      width: w,
      height: h,
      display: "block",
      objectFit: srcComputed.objectFit,
      objectPosition: srcComputed.objectPosition,
    });

    while (lightbox.firstChild) lightbox.removeChild(lightbox.firstChild);
    lightbox.appendChild(cloneEl);

    const dstRect = cloneEl.getBoundingClientRect();
    const flip = computeFlip(srcRect, dstRect);

    lightbox.setAttribute("aria-hidden", "false");
    document.documentElement.style.cursor = "zoom-out";

    const tl = gsap.timeline({
      onComplete: () => {
        isAnimating = false;
        isOpen = true;
        attachCloseListeners();
      },
    });

    tl.to(lightbox, {
      backgroundColor: backdropColor,
      duration: 0.3,
      ease: "none",
    }, 0);

    tl.fromTo(
      cloneEl,
      { x: flip.tx, y: flip.ty, scaleX: flip.scaleX, scaleY: flip.scaleY },
      { x: 0, y: 0, scaleX: 1, scaleY: 1, duration: CONFIG.openDuration, ease: CONFIG.openEase },
      0
    );
  }

  function close() {
    if (!isOpen || isAnimating) return;
    isAnimating = true;
    detachCloseListeners();
    document.documentElement.style.cursor = "";

    const dstRect = cloneEl.getBoundingClientRect();
    const startX = Number(gsap.getProperty(cloneEl, "x")) || 0;
    const startY = Number(gsap.getProperty(cloneEl, "y")) || 0;
    const startScaleX = Number(gsap.getProperty(cloneEl, "scaleX")) || 1;
    const startScaleY = Number(gsap.getProperty(cloneEl, "scaleY")) || 1;

    function currentSrcRect() {
      return {
        top: openSourceRectDoc.top - window.scrollY,
        left: openSourceRectDoc.left,
        width: openSourceRectDoc.width,
        height: openSourceRectDoc.height,
      };
    }

    let lastFlip = computeFlip(currentSrcRect(), dstRect);

    const cleanup = () => {
      gsap.set(lightbox, { display: "none", clearProps: "backgroundColor" });
      if (cloneEl && cloneEl.parentNode) cloneEl.parentNode.removeChild(cloneEl);
      cloneEl = null;
      lightbox.setAttribute("aria-hidden", "true");
      openSourceRectDoc = null;
      isOpen = false;
      isAnimating = false;
    };

    const state = { t: 0 };

    gsap.to(state, {
      t: 1,
      duration: CONFIG.closeDuration,
      ease: CONFIG.closeEase,
      onUpdate: () => {
        lastFlip = computeFlip(currentSrcRect(), dstRect);
        const t = state.t;
        gsap.set(cloneEl, {
          x: startX + (lastFlip.tx - startX) * t,
          y: startY + (lastFlip.ty - startY) * t,
          scaleX: startScaleX + (lastFlip.scaleX - startScaleX) * t,
          scaleY: startScaleY + (lastFlip.scaleY - startScaleY) * t,
        });
      },
      onComplete: cleanup,
    });

    gsap.to(lightbox, {
      backgroundColor: transparent,
      duration: 0.3,
      ease: "power2.in",
      delay: CONFIG.closeDuration * 0.4,
    });
  }

  function onDocumentClick(e) {
    // Article mode: every descendant <img> in a wrapper is clickable.
    const article = e.target.closest("[data-click-zoom-article]");
    if (article) {
      const img = e.target.closest("img");
      if (img && article.contains(img)) {
        e.preventDefault();
        open(img);
        return;
      }
    }
    // Explicit trigger on the <img> or a wrapper.
    const trigger = e.target.closest("[data-click-zoom]");
    if (!trigger) return;
    const img = trigger.tagName === "IMG" ? trigger : trigger.querySelector("img");
    if (!img) return;
    e.preventDefault();
    open(img);
  }

  function onOverlayClick() { if (CONFIG.closeOnClick) close(); }
  function onKeyDown(e) { if (CONFIG.closeOnEscape && e.key === "Escape") close(); }
  function onScroll() {
    if (!CONFIG.closeOnScroll) return;
    if (Math.abs(window.scrollY - openScrollY) < 2) return;
    close();
  }

  function attachCloseListeners() {
    lightbox.addEventListener("click", onOverlayClick);
    document.addEventListener("keydown", onKeyDown);
    window.addEventListener("scroll", onScroll, { passive: true });
  }

  function detachCloseListeners() {
    lightbox.removeEventListener("click", onOverlayClick);
    document.removeEventListener("keydown", onKeyDown);
    window.removeEventListener("scroll", onScroll);
  }

  document.addEventListener("click", onDocumentClick);
}




// -----------------------------------------
// CMD+ZEST — QUIZ
// -----------------------------------------

function initCMDZestQuiz(scope) {
  const core = initQuizCore();
  core.clearAnswers();
  initQuizLogic(core, scope);
  initQuizFrame(() => initQuizInteraction(scope), scope);
}
 
/* ============================================================
   initQuizCore()
   Defines the scoring config and shared storage/scoring helpers.
   Returns them as an object used by initQuizLogic().
   Scoring dimensions: [CH, SP, IN, PF, DE]
   CH = Chaos · SP = Speed · IN = Instinct · PF = Perfectionism · DE = Deadline Energy
   ============================================================ */
function initQuizCore() {
  const CONFIG = {
    storageKey: 'cmdzest_answers',
    resultKey: 'cmdzest_result',
    outcomeBasePath: '/cmd-zest/',
    scoring: {
      q0: { a: [ 0,  3,  2, -1,  0], b: [ 2, -1,  0,  0,  3], c: [-1, -2,  0,  3,  0] },
      q1: { a: [ 0, -3,  1,  2,  2], b: [ 2,  1,  4, -2,  1] },
      q2: { a: [ 0,  2,  0,  0,  4], b: [ 4,  0,  1,  0,  2], c: [-1,  4,  0,  0,  0] },
      q3: { a: [ 1, -1,  3,  0,  1], b: [ 4,  1,  0, -1,  2], c: [ 0, -2,  0,  4,  0] },
      q4: { a: [ 1, -1,  4,  1,  0], b: [ 2,  4,  0, -1,  3], c: [-1, -3,  0,  5,  1] }
    },
    outcomes: [
      { slug: 'never-finished', test: s => s.PF >= 11 && s.SP <= -2 },
      { slug: 'chaos',          test: s => s.CH >= 9  && s.SP <=  5 },
      { slug: 'first-instinct', test: s => s.IN >= 8  && s.CH <=  3 },
      { slug: 'vibes',          test: s => s.SP >= 7  && s.IN >=  3 && s.PF <= 1 },
      { slug: 'deadline',       test: s => s.DE >= 8  && s.SP >=  1 && s.CH <= 5 },
      { slug: 'midnight',       test: s => s.DE >= 6  && s.CH >=  6 },
      { slug: 'over-think',     test: s => s.PF >= 7  && s.SP <=  0 },
      { slug: 'slowburn',       test: s => s.SP <= -3 && s.PF <=  6 },
    ],
    fallback: 'zest'
  };
 
  function readAnswers() {
    try { return JSON.parse(sessionStorage.getItem(CONFIG.storageKey)) || {}; } catch (e) { return {}; }
  }
  function writeAnswers(answers) {
    sessionStorage.setItem(CONFIG.storageKey, JSON.stringify(answers));
  }
  function clearAnswers() {
    sessionStorage.removeItem(CONFIG.storageKey);
  }
  function calculateShortcut(answers) {
    const totals = [0, 0, 0, 0, 0];
    Object.keys(answers).forEach(qKey => {
      const row = CONFIG.scoring[qKey]?.[answers[qKey]];
      if (row) row.forEach((v, i) => totals[i] += v);
    });
    const s = { CH: totals[0], SP: totals[1], IN: totals[2], PF: totals[3], DE: totals[4] };
    const match = CONFIG.outcomes.find(o => o.test(s));
    return { slug: match ? match.slug : CONFIG.fallback, scores: s };
  }
 
  return { CONFIG, readAnswers, writeAnswers, clearAnswers, calculateShortcut };
}
 
/* ============================================================
   initQuizLogic(core, scope)
   Handles: answer selection, sessionStorage, progress bar,
   scoring, and redirect on submit.
   scope — the Barba container element (defaults to document)
   ============================================================ */
function initQuizLogic(core, scope = document) {
  const { CONFIG, readAnswers, writeAnswers, clearAnswers, calculateShortcut } = core;
 
  const root = scope.querySelector('[data-cmd-quiz]') || scope.querySelector('.cmd-quiz');
  if (!root) return;
 
  const questions = [...root.querySelectorAll('.cmd-quiz__question[data-question]')];
  const submitBtn = root.querySelector('[data-cmd-submit]');
  let answers = {};
 
  function updateProgress() {
    const fill = scope.querySelector('[data-cmd-progress]');
    if (!fill) return;
    const answered = questions.filter(q => !!answers[q.dataset.question]).length;
    fill.style.width = (questions.length ? Math.round((answered / questions.length) * 100) : 0) + '%';
  }
 
  function setError(msg) {
    const node = scope.querySelector('[data-cmd-error]');
    if (!node) return;
    node.textContent = msg || '';
    node.style.display = msg ? '' : 'none';
  }
 
  updateProgress();
 
  // Answer selection
  root.addEventListener('click', e => {
    const answerEl = e.target.closest('.cmd-answer');
    if (!answerEl || !root.contains(answerEl)) return;
 
    const questionEl = answerEl.closest('.cmd-quiz__question');
    if (!questionEl) return;
 
    const qKey = questionEl.dataset.question;
    const aVal = answerEl.dataset.answer;
    if (!qKey || !aVal) return;
 
    if (answerEl.tagName === 'BUTTON') e.preventDefault();
 
    questionEl.querySelectorAll('.cmd-answer').forEach(sib => sib.classList.remove('is-selected'));
    answerEl.classList.add('is-selected');
    questionEl.classList.add('is-answered');
 
    answers[qKey] = aVal;
    writeAnswers(answers);
    updateProgress();
    setError('');
 
    const tabEl = root.querySelector(`[data-quiz-tab="${qKey}"]`);
    if (tabEl) tabEl.classList.add('is-answered');
  });
 
  // Submit — triggered by cmdzest:do-submit event or optional [data-cmd-submit] button.
  // The handler is stored on window so it can be removed on re-init (prevents
  // duplicate listeners accumulating across Barba page navigations).
function submit() {
  // Redirect to demo/CTA page — update this URL as needed
  const ctaUrl = 'https://segunda-p-gina-do-quiz.vercel.app/';
  try { sessionStorage.setItem('quiz_completed', 'true'); } catch {}
  window.location.href = ctaUrl;
}
 
  if (window._cmdzestSubmitHandler) {
    document.removeEventListener('cmdzest:do-submit', window._cmdzestSubmitHandler);
  }
  window._cmdzestSubmitHandler = submit;
  document.addEventListener('cmdzest:do-submit', submit);
 
  if (submitBtn) {
    submitBtn.addEventListener('click', e => { e.preventDefault(); submit(); });
  }
 
  // Debug API
  window.CMDZEST = {
    getAnswers: readAnswers,
    getScores:  () => calculateShortcut(readAnswers()).scores,
    getResult:  () => calculateShortcut(readAnswers()),
    reset() {
      clearAnswers();
      answers = {};
      questions.forEach(q => {
        q.classList.remove('is-answered');
        q.querySelectorAll('.cmd-answer').forEach(a => a.classList.remove('is-selected'));
      });
      root.querySelectorAll('[data-quiz-tab]').forEach(t => t.classList.remove('is-answered'));
      updateProgress();
      setError('');
      document.dispatchEvent(new CustomEvent('cmdzest:reset'));
    }
  };
}
 
/* ============================================================
   initQuizInteraction(scope)
   Handles: one-question-at-a-time visibility, GSAP-driven
   transitions, transition screens, tab navigation, keyboard
   input, and auto-submit after the last answer.
   scope — the Barba container element (defaults to document)
   ============================================================ */
function initQuizInteraction(scope = document) {
  // ~78 BPM — timing locked to the 8th note grid (0.19s)
  const EIGHTH         = 0.19;
  const BEAT           = 0.77;
  const CHAR_STAGGER   = 0.025;  // tight char stagger for typewriter snap
  const BUTTON_STAGGER = EIGHTH;
  const ENTER_DUR      = 0.38;   // half beat
  const EXIT_DUR       = 0.22;   // percussive cut
  const HOLD           = BEAT;   // transition screen hold
  const IN_EASE        = 'back.out(2)';
  const OUT_EASE       = 'power3.in';

  const root = scope.querySelector('[data-cmd-quiz]') || scope.querySelector('.cmd-quiz');
  if (!root) return;

  const questions   = [...root.querySelectorAll('.cmd-quiz__question[data-question]')];
  const transitions = [...root.querySelectorAll('.cmd-quiz__transition[data-transition]')];
  const tabs        = [...root.querySelectorAll('[data-quiz-tab]')];
  if (!questions.length) return;

  let advancing = false;

  // Helper: is a screen a copy (no answer choices, just a continue button)?
  function isCopyScreen(q) {
    return q.dataset.screenType === 'copy';
  }

  // Helper: is the final CTA screen?
  function isFinalScreen(q) {
    return q.hasAttribute('data-screen-final');
  }

  // Split all titles into chars at init
  const charSplits = new Map();
  questions.forEach(q => {
    const title = q.querySelector('[data-cmd-question-title]');
    if (!title) return;
    const split = new SplitText(title, { type: 'words, chars', autoSplit:true });
    gsap.set(split.chars, { opacity: 0, y: 20 });
    charSplits.set(q, split);
  });

  const getAnswers = q => [...q.querySelectorAll('.cmd-answer')];

  function setActiveTab(idx) {
    tabs.forEach(t => t.classList.remove('is-active'));
    tabs.find(t => t.dataset.quizTab === `q${idx}`)?.classList.add('is-active');
  }

  // Mark a tab as visited (answered or seen for copies)
  function markTabVisited(idx) {
    const tabEl = tabs.find(t => t.dataset.quizTab === `q${idx}`);
    if (tabEl) tabEl.classList.add('is-answered');
  }

  function hideQuestion(q) {
    const split = charSplits.get(q);
    if (split) gsap.set(split.chars, { opacity: 0, y: 20 });
    gsap.set(getAnswers(q), { opacity: 0, y: 16 });
  }

  // Chars snap in letter-by-letter, buttons follow on the 8th-note grid
  function enterQuestion(q) {
    const tl        = gsap.timeline();
    const split     = charSplits.get(q);
    const btns      = getAnswers(q);
    const charCount = split?.chars.length ?? 0;

    if (split) {
      tl.to(split.chars, {
        opacity: 1, y: 0, duration: ENTER_DUR, ease: IN_EASE,
        stagger: CHAR_STAGGER
      });
    }
    tl.to(btns, {
      opacity: 1, y: 0, duration: ENTER_DUR, ease: IN_EASE,
      stagger: BUTTON_STAGGER
    }, charCount * CHAR_STAGGER + ENTER_DUR * 0.4);

    return tl;
  }

  // Buttons sweep out in reverse, chars follow — both fully animated
  function exitQuestion(q, tl) {
    const split = charSplits.get(q);

    tl.to(getAnswers(q), {
      opacity: 0, y: -12, duration: EXIT_DUR, ease: OUT_EASE,
      stagger: { each: BUTTON_STAGGER * 0.5, from: 'end' }
    });
    if (split) {
      tl.to(split.chars, {
        opacity: 0, y: -16, duration: EXIT_DUR, ease: OUT_EASE,
        stagger: { each: CHAR_STAGGER * 0.5, from: 'end' }
      }, '<0.05');
    }
    tl.call(() => {
      q.classList.remove('is-active');
      gsap.set(q, { opacity: 0 });
    });
  }

  // --- Shared advance logic: moves from current screen to next ---
  function advanceFromScreen(questionEl, markAsAnswered) {
    if (advancing) return;

    const idx          = questions.indexOf(questionEl);
    if (idx === -1) return;
    const isLast       = idx === questions.length - 1;
    const transitionEl = transitions.find(t => t.dataset.transition === `q${idx}`);
    const next         = isLast ? null : questions[idx + 1];

    advancing = true;
    const tl = gsap.timeline({ onComplete: () => { advancing = false; } });

    tl.to({}, { duration: EIGHTH }); // selection pause

    // Mark the current tab as visited
    if (markAsAnswered) markTabVisited(idx);

    exitQuestion(questionEl, tl);

    if (transitionEl) {
      tl.call(() => {
        gsap.set(transitionEl, { opacity: 0, y: 16 });
        transitionEl.classList.add('is-active');
      });
      tl.to(transitionEl, { opacity: 1, y: 0, duration: ENTER_DUR, ease: IN_EASE });
      tl.to({}, { duration: HOLD });
      tl.to(transitionEl, { opacity: 0, y: -16, duration: EXIT_DUR, ease: OUT_EASE });
      tl.call(() => transitionEl.classList.remove('is-active'));
    }

    if (isLast) {
      // Wind-down exit — quiz frame scales + spins out before redirect
      tl.to(tabs, { autoAlpha: 0 });
      tl.to(root, {
        scale: 1.06,
        rotation: -5,
        duration: 0.25,
        ease: 'power2.out',
        transformOrigin: '50% 50%'
      });
      tl.to(root, {
        scale: 0.2,
        rotation: 18,
        autoAlpha: 0,
        duration: 0.75,
        ease: 'expo.in',
        transformOrigin: '50% 50%'
      });
      tl.call(() => document.dispatchEvent(new CustomEvent('cmdzest:do-submit')));
    } else {
      tl.call(() => {
        setActiveTab(idx + 1);
        // Auto-mark copy screens as visited when they become active
        if (isCopyScreen(next)) markTabVisited(idx + 1);
        next.classList.add('is-active');
        gsap.set(next, { opacity: 1 });
        hideQuestion(next);
      });
      tl.add(enterQuestion(next));
    }
  }

  // --- Initial state ---
  gsap.set([...questions, ...transitions], { opacity: 0 });
  questions.forEach(hideQuestion);
  questions[0].classList.add('is-active');
  gsap.set(questions[0], { opacity: 1 });
  setActiveTab(0);
  // If the first screen is a copy, mark it visited immediately
  if (isCopyScreen(questions[0])) markTabVisited(0);
  enterQuestion(questions[0]);

  // --- Answer click (for question screens) ---
  root.addEventListener('click', e => {
    if (advancing) return;

    const answerEl   = e.target.closest('.cmd-answer');
    if (!answerEl || !root.contains(answerEl)) return;
    const questionEl = answerEl.closest('.cmd-quiz__question');
    if (!questionEl) return;

    // Copy screen: [data-copy-next] button advances to next screen
    if (answerEl.hasAttribute('data-copy-next')) {
      e.preventDefault();
      advanceFromScreen(questionEl, true);
      return;
    }

    // Regular question screen: answer selection
    if (answerEl.tagName === 'BUTTON') e.preventDefault();
    questionEl.querySelectorAll('.cmd-answer').forEach(sib => sib.classList.remove('is-selected'));
    answerEl.classList.add('is-selected');
    questionEl.classList.add('is-answered');
    
    advanceFromScreen(questionEl, true);
  });

  // --- Tab navigation (only for screens that have been visited) ---
  tabs.forEach(tab => {
    tab.addEventListener('click', () => {
      if (advancing) return;
      if (!tab.classList.contains('is-answered')) return;

      const targetIdx = questions.findIndex(q => q.dataset.question === tab.dataset.quizTab);
      const current   = questions.find(q => q.classList.contains('is-active'));
      if (!current || questions.indexOf(current) === targetIdx) return;

      advancing = true;
      const tl = gsap.timeline({ onComplete: () => { advancing = false; } });

      exitQuestion(current, tl);
      tl.call(() => {
        setActiveTab(targetIdx);
        questions[targetIdx].classList.add('is-active');
        gsap.set(questions[targetIdx], { opacity: 1 });
        hideQuestion(questions[targetIdx]);
      });
      tl.add(enterQuestion(questions[targetIdx]));
    });
  });

  // --- Keyboard (a/b/c for question screens only) ---
  function handleKeydown(e) {
    if (advancing) return;
    const current = questions.find(q => q.classList.contains('is-active'));
    if (!current) return;
    // On copy screens, Enter/Space advances
    if (isCopyScreen(current)) {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        current.querySelector('[data-copy-next]')?.click();
      }
      return;
    }
    if (!['a', 'b', 'c'].includes(e.key.toLowerCase())) return;
    current?.querySelector(`.cmd-answer[data-answer="${e.key.toLowerCase()}"]`)?.click();
  }

  if (window._cmdzestKeydownHandler) document.removeEventListener('keydown', window._cmdzestKeydownHandler);
  window._cmdzestKeydownHandler = handleKeydown;
  document.addEventListener('keydown', handleKeydown);

  // --- Reset ---
  function handleReset() {
    advancing = false;
    gsap.killTweensOf([...questions, ...transitions]);
    charSplits.forEach(s => gsap.killTweensOf(s.chars));

    gsap.set([...questions, ...transitions], { opacity: 0 });
    questions.forEach(q => {
      q.classList.remove('is-active');
      q.querySelectorAll('.cmd-answer').forEach(a => a.classList.remove('is-selected'));
      hideQuestion(q);
    });
    transitions.forEach(t => t.classList.remove('is-active'));
    tabs.forEach(t => { t.classList.remove('is-active'); t.classList.remove('is-answered'); });

    questions[0].classList.add('is-active');
    gsap.set(questions[0], { opacity: 1 });
    setActiveTab(0);
    if (isCopyScreen(questions[0])) markTabVisited(0);
    enterQuestion(questions[0]);
  }

  if (window._cmdzestResetHandler) document.removeEventListener('cmdzest:reset', window._cmdzestResetHandler);
  window._cmdzestResetHandler = handleReset;
  document.addEventListener('cmdzest:reset', handleReset);
}

/* ============================================================
   initQuizFrame(onComplete, scope)
   Animates the .cmd-quiz container scaling up from center.
   Fires onComplete when the frame has fully expanded, which
   is when initQuizInteraction() is called.
   ============================================================ */
function initQuizFrame(onComplete, scope = document) {
  const quiz = scope.querySelector('[data-cmd-quiz]') || scope.querySelector('.cmd-quiz');
  if (!quiz) { if (onComplete) onComplete(); return; }
 
  gsap.set(quiz, { scaleX: 0, opacity: 0, rotate: 25, transformOrigin: '50% 50%' });
  gsap.to(quiz, {
    scaleX: 1,
    opacity: 1,
    rotate: 0,
    delay: 0.5,
    duration: .75,
    ease: 'main',
    onComplete: onComplete
  });
}
 
/* ============================================================
   initCMDAudio()
   Called once from initOnceFunctions — Howl instances persist
   across Barba page transitions.
   DOM contract:
     [data-audio-start]  → one-time start button (gets .is-hidden after click)
     [data-audio-toggle] → play/pause toggle (gets .is-playing while active)
   ============================================================ */
function initCMDAudio() {
  let audioActive = false;
 
  const bgMusic = new Howl({
    src: ['https://sour.b-cdn.net/cmd-zest/Sour-Track.mp3'],
    loop: true,
    volume: 0.1,
    html5: true
  });
 
  const answerSounds = {
    a: new Howl({ src: ['https://sour.b-cdn.net/cmd-zest/Sour-button1.mp3'], volume: 0.1 }),
    b: new Howl({ src: ['https://sour.b-cdn.net/cmd-zest/Sour-button3.mp3'], volume: 0.1 }),
    c: new Howl({ src: ['https://sour.b-cdn.net/cmd-zest/Sour-button5.mp3'], volume: 0.1 })
  };
 
  const startBtn  = document.querySelector('[data-audio-start]');
  const toggleBtn = document.querySelector('[data-audio-toggle]');
 
  function startAudio() {
    bgMusic.play();
    audioActive = true;
    if (startBtn)  startBtn.classList.add('is-hidden');
    if (toggleBtn) toggleBtn.classList.add('is-playing');
  }
 
  function toggleAudio() {
    if (bgMusic.playing()) {
      bgMusic.pause();
      audioActive = false;
      toggleBtn.classList.remove('is-playing');
    } else {
      bgMusic.play();
      audioActive = true;
      toggleBtn.classList.add('is-playing');
    }
  }
 
  if (startBtn)  startBtn.addEventListener('click', startAudio);
  if (toggleBtn) toggleBtn.addEventListener('click', toggleAudio);
 
  // Answer sounds — fires on any .cmd-answer click, only when audio is active
  document.addEventListener('click', e => {
    if (!audioActive) return;
    const answerEl = e.target.closest('.cmd-answer');
    if (!answerEl) return;
    const sound = answerSounds[answerEl.dataset.answer];
    if (sound) sound.play();
  });
}

function initDownloadButtons() {
  const selector = '[data-download-src]';
  const attrSrc = 'data-download-src';
  const attrName = 'data-download-name';
  const setState = (el, state) => { el.dataset.downloadState = state; };
  const triggerDownload = (url, filename) => {
    const a = document.createElement('a');
    a.href = url;
    if (filename) a.download = filename;
    a.rel = 'noopener';
    a.style.display = 'none';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };
  document.querySelectorAll(selector).forEach(el => {
    setState(el, 'idle');
    const labelEl = el.querySelector('[data-download-label]');
    if (labelEl && !labelEl.dataset.downloadOriginalLabel) {
      labelEl.dataset.downloadOriginalLabel = labelEl.textContent;
    }
    const showSuccessAndReset = () => {
      if (labelEl) {
        const successText = labelEl.getAttribute('data-download-success');
        if (successText) labelEl.textContent = successText;
      }
      if (el._downloadResetTimeout) clearTimeout(el._downloadResetTimeout);
      el._downloadResetTimeout = setTimeout(() => {
        setState(el, 'idle');
        if (labelEl) {
          const original = labelEl.dataset.downloadOriginalLabel;
          if (original != null) labelEl.textContent = original;
        }
      }, 3000);
    };
    el.addEventListener('click', async (e) => {
      e.preventDefault();
      if (el.dataset.downloadState === 'downloading') return;
      const src = el.getAttribute(attrSrc);
      if (!src) return;
      const customName = el.getAttribute(attrName);
      const urlObj = new URL(src, window.location.href);
      const urlFilePart = urlObj.pathname.split('/').pop() || 'download';
      const fileName = customName || urlFilePart;
      el.blur();
      try {
        setState(el, 'downloading');
        const res = await fetch(src, { mode: 'cors', credentials: 'omit' });
        if (!res.ok) throw new Error('bad status');
        const blob = await res.blob();
        const objectUrl = URL.createObjectURL(blob);
        setState(el, 'ready');
        triggerDownload(objectUrl, fileName);
        showSuccessAndReset();
        setTimeout(() => URL.revokeObjectURL(objectUrl), 10_000);
      } catch (err) {
        setState(el, 'fallback');
        triggerDownload(src, fileName);
        showSuccessAndReset();
      }
    });
  });
}

function initCMDSidebar() {
  const wrap = document.querySelector('[data-cmd-sidebar-wrap]');
  if (!wrap) return;
 
  const sidebar   = wrap.querySelector('[data-cmd-sidebar]');   // clipPath target
  const scrollEl  = sidebar?.querySelector('.cmd-sidebar__inner') || sidebar; // scroll target
  const overlay   = wrap.querySelector('[data-cmd-sidebar-overlay]');
  const fadeEls   = wrap.querySelectorAll('[data-cmd-sidebar-fade]');
  const openBtns  = document.querySelectorAll('[data-cmd-sidebar-open]');
  const closeBtns = document.querySelectorAll('[data-cmd-sidebar-close]');
  const scrollbar = wrap.querySelector('[data-cmd-scrollbar]');
  const thumb     = wrap.querySelector('[data-cmd-scrollbar-thumb]');
 
  const tl = gsap.timeline();
 
  // --- Scrollbar sync ---
  function updateThumb() {
    if (!scrollbar || !thumb) return;
    const { scrollTop, scrollHeight, clientHeight } = scrollEl;
    const scrollable = scrollHeight - clientHeight;
    if (scrollable <= 0) { gsap.set(scrollbar, { autoAlpha: 0 }); return; }
    const trackH = scrollbar.clientHeight;
    const thumbH = Math.max((clientHeight / scrollHeight) * trackH, 32);
    const thumbY = (scrollTop / scrollable) * (trackH - thumbH);
    gsap.set(thumb,     { height: thumbH, y: thumbY });
    gsap.set(scrollbar, { autoAlpha: 1 });
  }
 
  scrollEl.addEventListener('scroll', updateThumb, { passive: true });
 
  // --- Open / close ---
  const open = () => {
    
    wrap.setAttribute('data-sidebar-state', 'open');
    tl.clear()
      .set(wrap,    { display: 'block' })
      .fromTo(overlay,  { autoAlpha: 0 },                  { autoAlpha: 1 }, '<')
      .fromTo(sidebar,  { clipPath: 'inset(0 100% 0 0)' }, { clipPath: 'inset(0 0% 0 0)', ease: 'expo.out', duration: 0.7 }, '<')
      .fromTo(fadeEls,  { autoAlpha: 0, y: 16 },           { autoAlpha: 1, y: 0, stagger: 0.05 }, '<+=0.3')
      .call(updateThumb);
  };
 
  const close = () => {
  
    wrap.setAttribute('data-sidebar-state', 'closed');
    tl.clear()
      .to(sidebar,  { clipPath: 'inset(0 100% 0 0)', ease: 'power3.in', duration: 0.45 })
      .to(overlay,  { autoAlpha: 0 }, '<')
      .set(wrap,    { display: 'none' });
  };
 
  openBtns.forEach(btn  => btn.addEventListener('click', open));
  closeBtns.forEach(btn => btn.addEventListener('click', close));
  if (overlay) overlay.addEventListener('click', close);
 
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape' && wrap.getAttribute('data-sidebar-state') === 'open') close();
  });
}
 
function initCMDIntro() {
  const modal    = document.querySelector('[data-cmd-modal]');
  const soundBtn = document.querySelector('[data-cmd-modal-sound]');
  const muteBtn  = document.querySelector('[data-cmd-modal-mute]');
  const fadeEls  = [...document.querySelectorAll('[data-cmd-modal-fade]')];
  const heroTexts  = [...document.querySelectorAll('[data-cmd-hero-text]')];
  const introTexts = [...document.querySelectorAll('.cmd-intro__text')];
  const navEl      = document.querySelector('[data-cmd-nav]');

  // Split intro texts into chars for the loading sequence
  const introSplits = introTexts.map(el => SplitText.create(el, { type: 'words, chars', autoSplit: true }));

  // Split hero texts into chars — same style as quiz questions
  const heroSplits = heroTexts.map(el => SplitText.create(el, { type: 'words, chars', autoSplit: true }));

  const heroEl      = document.querySelector('.cmd-landing__hero');
  const heroButtons = document.querySelectorAll('[data-cmd-hero-button]');

  // Hide all animated elements immediately — prevents flash during modal dismiss
  gsap.set(introSplits.flatMap(s => s.chars),  { opacity: 0, y: 20 });
  gsap.set(heroSplits.flatMap(s => s.chars),   { opacity: 0, y: 20 });
  if (heroEl)             gsap.set(heroEl,       { scaleX: 0.2, rotation: -4, opacity: 0, transformOrigin: '50% 50%' });
  if (heroButtons.length) gsap.set(heroButtons,  { scale: 0, opacity: 0 });
  if (navEl)              gsap.set(navEl,        { opacity: 0, y: -20 });

  // Full sequence: intro texts → hero reveal
  function playIntroThenHero() {
    const tl = gsap.timeline();

    // Phase 1 — Intro texts animate in and out one by one
    introTexts.forEach((text, i) => {
      const chars = introSplits[i].chars;
      tl.fromTo(chars,
        { opacity: 0, y: 20 },
        { opacity: 1, y: 0, duration: 0.38, ease: 'back.out(2)', stagger: 0.025 }
      );
      tl.to({}, { duration: 0.55 }); // hold
      tl.to(chars,
        { opacity: 0, y: -16, duration: 0.22, ease: 'power3.in', stagger: { each: 0.012, from: 'end' } }
      );
    });

    // Phase 2 — Hero wrapper scales up
    if (heroEl) tl.fromTo(heroEl,
      { scaleX: 0.2, rotation: -4, opacity: 0, transformOrigin: '50% 50%' },
      { scaleX: 1,   rotation:  0, opacity: 1, duration: 1.1, ease: 'expo.out' },
      '+=0.1'
    );

    // Hero buttons pop in alongside
    if (heroButtons.length) tl.fromTo(heroButtons,
      { scale: 0, opacity: 0 },
      { scale: 1, opacity: 1, duration: 1.1, ease: 'expo.out', stagger: 0.25 },
      '<'
    );

    // Nav fades in
    if (navEl) tl.fromTo(navEl,
      { opacity: 0, y: -20 },
      { opacity: 1, y:   0, duration: 1, ease: 'power3.out' },
      '<+=0.15'
    );

    // Hero typography chars snap in
    heroTexts.forEach((text, i) => {
      tl.fromTo(heroSplits[i].chars,
        { opacity: 0, y: 20 },
        { opacity: 1, y: 0, duration: 0.38, ease: 'back.out(2)', stagger: { amount: 0.25 } },
        i === 0 ? '<+=0.2' : '<+=0.15'
      );
    });
  }

  // No modal — play immediately
  if (!modal) { playIntroThenHero(); return; }

  // Modal: fade in on load
  gsap.timeline()
    .fromTo(fadeEls, { opacity: 0, y: 20 }, { opacity: 1, y: 0, duration: 0.5, ease: 'power2.out', stagger: 0.08 });

  // On click: dismiss modal then run the full intro + hero sequence
  function dismiss() {
    gsap.timeline({ onComplete: () => { modal.remove(); playIntroThenHero(); } })
      .to(fadeEls, { opacity: 0, y: -16, duration: 0.3, ease: 'power2.in', stagger: 0.05 })
      .to(modal,   { autoAlpha: 0,       duration: 0.4, ease: 'power2.in' }, '<+=0.1');
  }

  soundBtn?.addEventListener('click', dismiss);
  muteBtn?.addEventListener('click',  dismiss);
}
 
function initGridHighlightLines() {
  if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) return;
  const lines = Array.from(document.querySelectorAll('.cmd-grid__highlight-line'));
  if (!lines.length) return;
  const TRAVEL_DUR = 2.2;
  const PAUSE_MIN  = 0.2;
  const PAUSE_MAX  = 1.0;
  let available = lines.map((_, i) => i);
  let lastIndex = -1;
  gsap.set(lines, { y: '-110vh' });
  function fireNext() {
    if (!available.length) return;
    let pick;
    if (available.length === 1) {
      pick = 0;
    } else {
      do { pick = Math.floor(Math.random() * available.length); }
      while (available[pick] === lastIndex);
    }
    const lineIndex = available.splice(pick, 1)[0];
    lastIndex = lineIndex;
    gsap.set(lines[lineIndex], { y: '-110vh' });
    gsap.to(lines[lineIndex], {
      y: '110vh', duration: TRAVEL_DUR, ease: 'none',
      onComplete: () => {
        available.push(lineIndex);
        gsap.delayedCall(PAUSE_MIN + Math.random() * (PAUSE_MAX - PAUSE_MIN), fireNext);
      }
    });
  }
  fireNext();
}

 function loadUnicornStudio() {
  if (window.UnicornStudio) return; // already loading or loaded
  window.UnicornStudio = { isInitialized: false };
  const script = document.createElement('script');
  script.src = 'https://cdn.jsdelivr.net/gh/hiunicornstudio/unicornstudio.js@v2.1.9/dist/unicornStudio.umd.js';
  script.onload = () => {
    if (document.querySelector('[data-us-project]')) UnicornStudio.init();
  };
  (document.head || document.body).appendChild(script);
}
 
function initUnicornStudio() {
  if (typeof UnicornStudio === 'undefined') return;
  UnicornStudio.init();
}

function initQuizResultLoad(scope = document) {
  const frame  = scope.querySelector('.creative-shortcut');
  if (!frame) return;

  const titleEls = [...scope.querySelectorAll('.shortcut__title h1, .shortcut__title h2, .shortcut__title p')];
  const image    = scope.querySelector('.shortcut__image-wrapper');
  const cta      = scope.querySelector('.shortcut_cta-wrapper');

  // Split all title text into chars
  const splits = titleEls.map(el => {
    const split = new SplitText(el, { type: 'words, chars', autoSplit: true });
    gsap.set(split.chars, { opacity: 0, y: 20 });
    return split;
  });

  gsap.set(frame, { scaleX: 0, opacity: 0, rotateX: 25, transformOrigin: '50% 50%' });
  if (image) gsap.set(image, { opacity: 0, y: 40 });
  if (cta)   gsap.set(cta,   { opacity: 0, y: 16 });

  const tl = gsap.timeline();

  tl.to(frame, { scaleX: 1, opacity: 1, rotateX: 0, delay: 0.3, duration: 1.5, ease: 'expo.out' });

  splits.forEach((split, i) => {
    tl.to(split.chars, {
      opacity: 1, y: 0, duration: 0.38, ease: 'back.out(2)', stagger: {amount:0.25}
    }, i === 0 ? '<+=0.2' : '<+=0.19');
  });

  if (image) tl.to(image, { opacity: 1, y: 0, duration: 0.6, ease: 'power3.out' }, '<+=0.1');
  if (cta)   tl.to(cta,   { opacity: 1, y: 0, duration: 0.5, ease: 'power2.out' }, '<+=0.1');
}

